; 魔女の隠れ家


name = 魔女の隠れ家Ｂ３
insideName = Ｂ３
upper = 魔女の隠れ家Ｂ２
lower = 魔女の隠れ家Ｂ４
pool = 魔女の隠れ家Ｂ３水中
level = 23
bgm = hideout
roof = stone
shadow = dark
sky = black
blank = rock
outfield = marble
antiWarp = true

; 各パーツ
━ = stoney
　 = marble
☆ = soilr
～ = pool
❑ = cube
／ = door
☖ = arch
⧻ = fence
︻ = panel
㊤ = ladderu
㊦ = ladderd

[map]
;---------------------------------------------------------------------------------------------------------------
;    0   1   2   3   4   5   6   7  
  ┏︻━━━━━━━━━━━━━━┓
 5┃④　　　　～～～　　　　③　　┃
  ┃　　　　　～～～　　　　　　　┃
 4┃　　❑　　～～～③　③　☆　③┃
  ┃　　　　　～～～　　　　　　　┃
 3┃　　　　　～～～　　　　③　　┃
  ┃　　　　　～～～　　　　　　　┃
 2┃　　❑　　～～～　　　　③　　┃
  ┃　　　　　～～～　　　　　　　┃
 1┃　　　　　～～～　　　　　　　┃
  ┣━━━━⧻┳━━━━━━⧻━━┫
 0┃㊤　　　①┃㊦　　　　　　　　┃
